import { assertThrows } from "assert";
import { createOurContext } from "../context/mod.ts";
import { generator } from "../generate/mod.ts";
import { type Tests, testing } from "./testing.ts";

const context = createOurContext();
context.label("branch");
context.theirs.flashOrg = 3;
const generate = generator(context);

// The bytes for these tests were generated by the last version of GAVRAsm
// that I could get hold of.

const tests: Tests = [
    [["", "BRBC", ["4", "branch"]], [0xf7, 0xe4]],
    [["", "BRBS", ["3", "branch"]], [0xf3, 0xdb]],
    [["", "BRCC", [     "branch"]], [0xf7, 0xd0]],
    [["", "BRCS", [     "branch"]], [0xf3, 0xc8]],
    [["", "BREQ", [     "branch"]], [0xf3, 0xc1]],
    [["", "BRGE", [     "branch"]], [0xf7, 0xbc]],
    [["", "BRHC", [     "branch"]], [0xf7, 0xb5]],
    [["", "BRHS", [     "branch"]], [0xf3, 0xad]],
    [["", "BRID", [     "branch"]], [0xf7, 0xa7]],
    [["", "BRIE", [     "branch"]], [0xf3, 0x9f]],
    [["", "BRLO", [     "branch"]], [0xf3, 0x90]],
    [["", "BRLT", [     "branch"]], [0xf3, 0x8c]],
    [["", "BRMI", [     "branch"]], [0xf3, 0x82]],
    [["", "BRNE", [     "branch"]], [0xf7, 0x79]],
    [["", "BRPL", [     "branch"]], [0xf7, 0x72]],
    [["", "BRSH", [     "branch"]], [0xf7, 0x68]],
    [["", "BRTC", [     "branch"]], [0xf7, 0x66]],
    [["", "BRTS", [     "branch"]], [0xf3, 0x5e]],
    [["", "BRVC", [     "branch"]], [0xf7, 0x53]],
    [["", "BRVS", [     "branch"]], [0xf3, 0x4b]]
];

testing(tests, generate);

Deno.test("Absolute address too high on BRNE instruction", () => {
    context.theirs.flashOrg = 0;
    assertThrows(
        () => generate(["", "BRNE", ["130"]]),
        RangeError,
        "Operand out of range: should be relative branch to 7 bit range (-64 - 63) not 130"
    );
});

Deno.test("Absolute address too low on BREQ instruction", () => {
    context.theirs.flashOrg = 500;
    assertThrows(
        () => generate(["", "BREQ", ["100"]]),
        RangeError,
        "Operand out of range: should be relative branch to 7 bit range (-64 - 63) not 100"
    );
});
